INSERT INTO books (id, rank, title, author, year, pages, notes, film_adaptation, section_type, section_name, section_order, section_subtitle, cluster_vibe, order_in_section)
VALUES
  (185, NULL, 'Fifteen Dogs', 'André Alexis', 2015, 171, 'The gods Hermes and Apollo bet on whether human consciousness would make animals happy or miserable. Fifteen dogs get to find out. A Giller Prize winner that''s funnier and stranger than it has any right to be. (via @lucaskoakeley on Instagram)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  (186, NULL, 'The Leopard', 'Giuseppe Tomasi di Lampedusa', 1958, 280, 'An aging Sicilian prince watches his world dissolve during the Risorgimento. The source of the famous line: "If we want things to stay as they are, things will have to change." A cornerstone of Italian literature. (via @lucaskoakeley on Instagram)', '1963 film directed by Luchino Visconti, starring Burt Lancaster.', NULL, NULL, NULL, NULL, NULL, NULL),
  (187, NULL, 'The Ten Loves of Mr Nishino', 'Hiromi Kawakami', 2018, 192, 'Ten chapters, each from the perspective of a different woman who loved Mr. Nishino. A portrait of a man assembled entirely from the women he left behind. (via @lucaskoakeley on Instagram)', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  (188, NULL, 'Victoria', 'Knut Hamsun', 1898, 136, 'A miller''s son is in love with a landowner''s daughter. A short, lyrical tragedy about class, longing, and the cruelty of circumstance — from the Nobel laureate. (via @lucaskoakeley on Instagram)', NULL, NULL, NULL, NULL, NULL, NULL, NULL)
